class Solution {
public:
    int countWinningSequences(string s) {
        int n = s.size();
        int mod = 1e9 + 7;
        vector<vector<int>> dp(n + 1, vector<int>(3, 0));
        dp[0][0] = 1;
        for (int i = 1; i <= n; i++) {
            if (s[i - 1] == 'F') {
                dp[i][1] = (dp[i - 1][0] + dp[i - 1][2]) % mod;
                dp[i][2] = dp[i - 1][1];
            } else if (s[i - 1] == 'W') {
                dp[i][0] = (dp[i - 1][1] + dp[i - 1][2]) % mod;
                dp[i][2] = dp[i - 1][0];
            } else {
                dp[i][1] = (dp[i - 1][0] + dp[i - 1][2]) % mod;
                dp[i][0] = dp[i - 1][1];
            }
        }
        int res = 0;
        for (int i = 0; i < 3; i++) {
            res = (res + dp[n][i]) % mod;
        }
        return res;
    }
};
